    composer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2)); composer.setSize(W, H);
    composer.addPass(new RenderPass(scene, camera));
    composer.addPass(new UnrealBloomPass(new THREE.Vector2(W, H), 1.2, 0.6, 0.08));
    let mx = 0, my = 0;
    this._onMove = (e) => { mx = e.clientX / window.innerWidth - 0.5; my = e.clientY / window.innerHeight - 0.5; };
    window.addEventListener('mousemove', this._onMove);
